#include <stdio.h>
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);
        char grid[n][m];
        for (int i = 0; i < n; i++) {
            scanf("%s", grid[i]);
        }
        int count = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (grid[i][j] != '#') {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

