const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let t;
let input = [];
readline.on('line', line => {
    if (i === 0) {
        t = parseInt(line);
    } else {
        input.push(line);
    }
    i++;
    if (i === t * 2 + 1) {
        for (let j = 0; j < t; j++) {
            let [n, m] = input[j * 2].split(' ').map(x => parseInt(x));
            let grid = [];
            for (let k = 0; k < n; k++) {
                grid.push(input[j * 2 + 1 + k]);
            }
            let count = 0;
            for (let k = 0; k < n; k++) {
                for (let l = 0; l < m; l++) {
                    if (grid[k][l] !== '#') {
                        count++;
                    }
                }
            }
            console.log(count);
        }
    }
